animations_ = tuple(
  tuple(zlib.decompress(base64.b64decode(picture)).decode() for picture in animation)
  for animation in ANIMATIONS_
)

def launch(oled, field):
  oled.invert(True)
  
  for animation in animations_:
    if field & 1 << animations_.index(animation):
      for _ in range(90 * 2 // len(animation)):
        for picture in animation:
          oled.draw(picture, 128).show()
          
  oled.fill(0).invert(False).show()
